CREATE TABLE IF NOT EXISTS ORCAMENTOS_MENSAIS (ID BIGSERIAL PRIMARY KEY, USUARIO_ID BIGINT NOT NULL, ANO INT NOT NULL, MES INT NOT NULL, SLUG VARCHAR(8) NOT NULL, DATA_INICIO DATE NOT NULL, DATA_FIM DATE NOT NULL, SEQ_RECEITA INT DEFAULT 0 NOT NULL, SEQ_DESPESA INT DEFAULT 0 NOT NULL);
ALTER TABLE ORCAMENTOS_MENSAIS ADD CONSTRAINT uk_orcamento_usuario_slug UNIQUE (USUARIO_ID, SLUG);
CREATE TABLE IF NOT EXISTS LANCAMENTOS_MENSAIS (ID BIGSERIAL PRIMARY KEY, ORCAMENTO_ID BIGINT NOT NULL, SLUG VARCHAR(20) NOT NULL, DESCRICAO VARCHAR(32) NOT NULL, VALOR DECIMAL(10, 2) NOT NULL, TIPO VARCHAR(10) NOT NULL, STATUS_DESPESA VARCHAR(10) NULL, CONSTRAINT FK_LANCAMENTOS_MENSAIS_ORCAMENTO_ID__ID FOREIGN KEY (ORCAMENTO_ID) REFERENCES ORCAMENTOS_MENSAIS(ID) ON DELETE RESTRICT ON UPDATE RESTRICT);
ALTER TABLE LANCAMENTOS_MENSAIS ADD CONSTRAINT uk_lancamento_orcamento_slug UNIQUE (ORCAMENTO_ID, SLUG);
